commands.examples:
CREATE ROLE admin WITH LOGIN SUPERUSER PASSWORD 'secret123';
CREATE USER app_user WITH PASSWORD 'pass123';
CREATE ROLE readonly;
CREATE ROLE developer WITH LOGIN CREATEDB PASSWORD 'dev123';

GRANT SELECT ON users TO readonly;
GRANT ALL PRIVILEGES ON ALL TABLES IN SCHEMA public TO admin;
GRANT USAGE ON SCHEMA public TO app_user;
GRANT SELECT, INSERT, UPDATE ON orders TO app_user;

-- Grant role ke role lain
GRANT readonly TO developer;

ALTER ROLE app_user WITH PASSWORD 'new_password';
ALTER ROLE developer WITH CREATEDB;
ALTER ROLE admin VALID UNTIL '2025-12-31';
DROP ROLE IF EXISTS old_user;
